return [{
  json: {
    status: 'not_found',
    message: 'ဒီပစ္စည်းက လက်ကျန်မရှိတော့ပါဘူးရှင်။',
    product_name: $('Parse Input Data').first().json.product_name
  }
}];

// အဝင် Data အားလုံးကို ယူမည် (.first() အစား .all() ကို သုံးသည်)
const allProducts = $input.all();
const allParsedData = $('Parse Input Data').all();

// Item တစ်ခုချင်းစီတိုင်းအတွက် အလုပ်လုပ်ပေးရန် .map() ဖြင့် Loop ပတ်မည်
const output = allProducts.map((item, index) => {
    const product = item.json;

    // အဝင် Product နဲ့ ၎င်းရဲ့ မူလ Parse လုပ်ထားတဲ့ Data ကို Index တူညီစွာဖြင့် တွဲပေးမည်
    const parsedData = allParsedData[index] ? allParsedData[index].json : $('Parse Input Data').first().json;

    const requestedQty = parseInt(parsedData.quantity) || 1;
    const instock = parseInt(product['Instock']) || 0;

    // Price tiers from Google Sheets
    const price1 = parseFloat(product['Price_Retail']) || 0;
    const price2 = parseFloat(product['Price_Wholesale']) || 0;
    const price3 = parseFloat(product['Price_Bulk']) || 0;
    const price4 = parseFloat(product['Price_SuperBulk']) || 0;
    const qty_tier2 = parseInt(product['Qty_Tier2']) || 5;
    const qty_tier3 = parseInt(product['Qty_Tier3']) || 20;
    const qty_tier4 = parseInt(product['Qty_Tier4']) || 0;

    // Determine price based on quantity (check highest tier first)
    let unitPrice = price1;
    let priceTier = 'Retail';
    if (qty_tier4 > 0 && price4 > 0 && requestedQty >= qty_tier4) {
        unitPrice = price4;
        priceTier = 'SuperBulk';
    } else if (requestedQty >= qty_tier3) {
        unitPrice = price3;
        priceTier = 'Bulk';
    } else if (requestedQty >= qty_tier2) {
        unitPrice = price2;
        priceTier = 'Wholesale';
    }

    const totalPrice = unitPrice * requestedQty;

    // Item တစ်ခုချင်းစီအတွက် JSON Format ဖြင့် ပြန်ထုတ်ပေးမည်
    return {
        json: {
            product_name: product['Product Name'],
            product_image: product['Product Image URL'] || '',
            requested_quantity: requestedQty,
            instock: instock,
            unit_price: unitPrice,
            price_tier: priceTier,
            total_price: totalPrice,
            price_retail: price1,
            price_wholesale: price2,
            price_bulk: price3,
            price_superbulk: price4,
            qty_tier2: qty_tier2,
            qty_tier3: qty_tier3,
            qty_tier4: qty_tier4,
            sender_id: parsedData.sender_id || '',
            action: parsedData.action || 'check',
            customer_name: parsedData.customer_name,
            customer_phone: parsedData.customer_phone,
            customer_address: parsedData.customer_address,
            payment_method: parsedData.payment_method
        }
    };
});

// Item အားလုံးပါဝင်သော Array ကြီးကို အပြီးသတ် ပြန်ထုတ်ပေးမည်
return output;

// 1. Grab the Telegram response (which is the current input)
const telegramResponse = $input.first().json;

// 2. We only need to store the message ID to track the Wait node
return [{
  json: {
    telegram_message_id: telegramResponse.message_id,
    order_status: 'pending_admin_approval',
    timestamp: new Date().toISOString()
  }
}];

// Webhook ကနေ Admin ရဲ့ အတည်ပြုချက်ကို ယူခြင်း (body ထဲက data များကို ယူပါသည်)
const webhookData = $input.first().json.body || $input.first().json;
const isApproved = webhookData.status === 'approved';

// Telegram မပို့ခင် သိမ်းထားခဲ့တဲ့ Order Summary ထဲက မူလပစ္စည်းအားလုံးကို ပြန်ယူခြင်း
const summaryData = $('Build Order Summary').first().json;
const originalItems = summaryData.all_items;

// Admin ငြင်းပယ်လိုက်လျှင်
if (!isApproved) {
    return [{
        json: {
            status: 'rejected',
            message: `ဝမ်းနည်းပါတယ်။ လက်ရှိမှာ ပစ္စည်းအချို့ လက်ကျန်မရှိတော့တဲ့အတွက် အော်ဒါကို ပယ်ဖျက်လိုက်ရပါတယ်ရှင်။`,
            sender_id: summaryData.sender_id
        }
    }];
}

// Telegram မှ ပြန်ဝင်လာသော အတည်ပြုထားသည့် ပစ္စည်းစာရင်း (Array)
const approvedItemsArray = webhookData.approved_items || [];

let finalCustomerMessage = `လူကြီးမင်းမှာယူထားသော ပစ္စည်းများအားလုံး အတည်ပြု (Confirm) လိုက်ပါပြီရှင်။ 🎉\n\n📌 အော်ဒါအနှစ်ချုပ်:\n`;
let grandTotal = 0;
const itemsToProcess = [];

// မူလမှာထားတဲ့ ပစ္စည်းတစ်ခုချင်းစီကို Admin အတည်ပြုတဲ့ အရေအတွက်နဲ့ တိုက်စစ်ခြင်း
originalItems.forEach((origItem) => {
    // Admin ပြန်ပို့လိုက်တဲ့ အထဲမှာ ဒီပစ္စည်း ပါ/မပါ ရှာမည်
    const matchedAdminItem = approvedItemsArray.find(i => i.product_name === origItem.product_name);

    // Admin ဆီက approved_qty ပါလာရင် အဲဒါကိုသုံးမည်၊ မပါလာရင် မူလမှာထားတဲ့ requested_quantity ကိုပဲ သုံးမည်
    let finalQty = origItem.requested_quantity; 
    if (matchedAdminItem && matchedAdminItem.approved_qty !== undefined) {
        finalQty = matchedAdminItem.approved_qty;
    }

    // အတည်ပြုအရေအတွက် 0 ထက်ကြီးမှသာ အော်ဒါအဖြစ် ဆက်လက်ဆောင်ရွက်မည်
    if (finalQty > 0) {
        // ကျသင့်ငွေကို အတည်ပြု အရေအတွက် အသစ်ဖြင့် ပြန်တွက်မည်
        const newTotalPrice = (parseFloat(origItem.unit_price) || 0) * finalQty;
        grandTotal += newTotalPrice;

        finalCustomerMessage += `• ${origItem.product_name} (${finalQty} ခု) - ${newTotalPrice} ကျပ်\n`;

        itemsToProcess.push({
            product_name: origItem.product_name,
            approved_qty: finalQty,
            new_stock: origItem.instock - finalQty, // လက်ကျန်အသစ်ကို approved_qty ဖြင့် နှုတ်သည်
            unit_price: origItem.unit_price
        });
    }
});

// Admin က အရေအတွက်တွေကို သုည(0) ပြောင်းလိုက်လို့ ပစ္စည်းတစ်ခုမှ မကျန်တော့ရင် Reject လုပ်မည်
if (itemsToProcess.length === 0) {
     return [{
        json: {
            status: 'rejected',
            message: `ဝမ်းနည်းပါတယ်။ လက်ရှိမှာ ပစ္စည်းအချို့ လက်ကျန်မရှိတော့တဲ့အတွက် အော်ဒါကို ပယ်ဖျက်လိုက်ရပါတယ်ရှင်။`,
            sender_id: summaryData.sender_id
        }
    }];
}

// -------------------------------------------------------------
// Customer ရွေးချယ်ခဲ့တဲ့ Payment Method ကို စစ်ဆေးခြင်း
// -------------------------------------------------------------
const paymentMethod = summaryData.payment_method || "";
let accountInfo = "";
if (paymentMethod.includes("KBZ") || paymentMethod.includes("Kpay")) {
    accountInfo = "🏦 KBZ Pay\n👤 အမည်: Ei Maung\n📞 အကောင့်: 091234567";
} else if (paymentMethod.includes("Wave")) {
    accountInfo = "🌊 Wave Pay\n👤 အမည်: Ei Maung\n📞 အကောင့်: 091234567";
} else if (paymentMethod.includes("CB")) {
    accountInfo = "🏦 CB Pay\n👤 အမည်: Ei Maung\n📞 အကောင့်: 091234567";
} else {
    accountInfo = "🏦 KBZ / CB / Wave Pay\n👤 အမည်: Ei Maung\n📞 အကောင့်: 091234567";
}

finalCustomerMessage += `\n💰 စုစုပေါင်း ကျသင့်ငွေ: ${grandTotal} ကျပ်\n\nလူကြီးမင်းရွေးချယ်ထားသော ငွေပေးချေမှုစနစ်အတွက် အောက်ပါအကောင့်သို့ လွှဲပေးနိုင်ပါတယ်ရှင်။\n\n${accountInfo}\n\nငွေလွှဲပြီးပါက ငွေလွှဲပြေစာ (Screenshot) လေး ပေးပို့ပေးပါရှင်။`;

// -------------------------------------------------------------
// Google Sheet ကို Update လုပ်ဖို့အတွက် Item တစ်ခုချင်းစီကို ပြန်ဖြန့်ထုတ်ခြင်း (Map)
// -------------------------------------------------------------
return itemsToProcess.map(item => ({
    json: {
        status: 'approved',
        product_name: item.product_name,
        new_stock: item.new_stock, // တွက်ထားပြီးသား လက်ကျန်အသစ်ကို ပို့ပေးမည်
        customer_message: finalCustomerMessage,
        sender_id: summaryData.sender_id
    }
}));

// ၁။ Trigger မှ Customer Data များကို ယူခြင်း
const orderData = $('Execute Workflow Trigger').first().json;

// ၂။ ရှေ့က Get Row မှ Database ထဲရှိ ခြင်းတောင်းအစစ်ကို ဆွဲထုတ်ခြင်း 
const dbData = $('Extract Cart Items').first().json;

let cartItems = [];
try {
    cartItems = JSON.parse(dbData.ai_json); // JSON ကို စနစ်တကျ ပြန်ဖြည်ခြင်း
} catch(e) {}

// ၃။ Final Order Sheet တွင် သိမ်းရန် သပ်ရပ်သော စာသားအဖြစ် ပြန်စီခြင်း (Summary)
let formattedOrderString = cartItems.map(item => {
    return `${item.product_name} (${item.quantity} ခု)`;
}).join('\n');

// ၄။ 🌟 ပစ္စည်းတစ်ခုချင်းစီအတွက် Google Sheets တွင် ရှာနိုင်ရန် Data များကို ခွဲထုတ်ခြင်း 🌟
let outputItems = cartItems.map(item => {
    return {
        json: {
            customer_name: orderData.customer_name,
            customer_phone: orderData.customer_phone,
            customer_address: orderData.customer_address,
            payment_method: orderData.payment_method,
            sender_id: orderData.sender_id,
            cart_summary: formattedOrderString, 
            total_items: cartItems.length,
            // အောက်ပါ ၂ ကြောင်းကို ထပ်တိုးလိုက်ခြင်းဖြင့် Sheets Node မှ အလွယ်တကူ ရှာဖွေနိုင်ပါမည်
            product_name: item.product_name,
            quantity: item.quantity
        }
    };
});

// အကယ်၍ ခြင်းတောင်းအလွတ် ဖြစ်နေခဲ့လျှင်
if (outputItems.length === 0) {
    return [{
        json: {
            customer_name: orderData.customer_name,
            sender_id: orderData.sender_id,
            cart_summary: "Empty Cart",
            product_name: "",
            quantity: 0
        }
    }];
}

// ခွဲထုတ်ထားသော ပစ္စည်းစာရင်းကို နောက် Node သို့ ပို့ပေးခြင်း
return outputItems;

// Return product info without triggering order/admin approval
const data = $input.first().json;

// Hardcoded Burmese response for the Product Info stage
const productResponse = `${data.product_name} ပစ္စည်းရှိပါတယ်ရှင်။

စျေးနှုန်းများမှာ -
• လက်လီစျေး: ${data.price_retail} MMK
• လက်ကားစျေး (${data.qty_tier2} ခုနှင့်အထက်): ${data.price_wholesale} MMK
• အများစျေး (${data.qty_tier3} ခုနှင့်အထက်): ${data.price_bulk} MMK
ဖြစ်ပါတယ်ရှင်။

ဒီပစ္စည်းကို မှာချင်ပါသလားရှင်?`;

return [{
  json: {
    status: 'product_info',
    product_name: data.product_name,
    product_image: data.product_image || '',
    unit_price: data.unit_price,
    price_tier: data.price_tier,
    total_price: data.total_price,
    message: productResponse // AI will repeat this exactly
  }
}];

const inputData = $input.first().json;

// လမ်းကြောင်းသစ် (Switch) ကလာတဲ့ Data ရော၊ အဟောင်းကလာတဲ့ Data ကိုပါ အလိုအလျောက် နားလည်အောင် ရေးထားခြင်း
const items = inputData.available_items || inputData.data || $input.all().map(i => i.json);

if (!items || items.length === 0) {
    return [{ json: { error: "No items found to build summary." } }];
}

let finalMessage = "==📦 <b>New Multi-Item Order</b>\n\n";
let grandTotal = 0;

// ပစ္စည်းတစ်ခုချင်းစီကို ဘေလ်ထဲ ထည့်ရေးခြင်း
items.forEach((item, index) => {
    finalMessage += `<b>${index + 1}. ${item.product_name}</b>\n`;
    finalMessage += `• Qty: ${item.requested_quantity} | Stock: ${item.instock}\n`;
    finalMessage += `• Price: ${item.total_price} MMK\n\n`;
    grandTotal += (parseFloat(item.total_price) || 0);
});

// Customer အချက်အလက်များ
const customer = items[0]; 
finalMessage += `💰 <b>Grand Total: ${grandTotal} MMK</b>\n\n`;
finalMessage += `👤 <b>--- CUSTOMER DETAILS ---</b>\n`;
finalMessage += `<b>Name:</b> ${customer.customer_name || 'N/A'}\n`;
finalMessage += `<b>Phone:</b> ${customer.customer_phone || 'N/A'}\n`;
finalMessage += `<b>Address:</b> ${customer.customer_address || 'N/A'}\n`;
finalMessage += `<b>Payment:</b> ${customer.payment_method || 'N/A'}\n`;
finalMessage += `<b>FB ID:</b> ${customer.sender_id || 'N/A'}\n\n`;

finalMessage += `💡 Reply with <code>approve</code> to confirm all items.`;

return [{
    json: {
        summary_message: finalMessage,
        grand_total: grandTotal,
        sender_id: customer.sender_id,
        payment_method: customer.payment_method,
        all_items: items // နောက်ပိုင်း အသုံးပြုရန်
    }
}];

// Aggregate ကနေ စုစည်းထားတဲ့ ပစ္စည်းအားလုံးကို ယူပါမယ်
const items = $input.first().json.data || $input.all().map(i => i.json);

let totalItems = items.length;
let outOfStockCount = 0;
let availableItems = [];
let oosItems = [];

items.forEach(item => {
    // လက်ကျန် 0 ဖြစ်နေသလား (သို့) တောင်းဆိုတဲ့ အရေအတွက်ထက် နည်းနေသလား စစ်ဆေးခြင်း
    if (item.instock === 0) {
        outOfStockCount++;
        oosItems.push(item);
    } else {
        availableItems.push(item);
    }
});

let cartStatus = "ALL_IN_STOCK";
if (outOfStockCount === totalItems) {
    cartStatus = "ALL_OOS"; // အားလုံး ကုန်နေတယ်
} else if (outOfStockCount > 0) {
    cartStatus = "PARTIAL_OOS"; // တချို့ရှိပြီး တချို့ကုန်နေတယ်
}

// ... (အပေါ်က code တွေက အတူတူပါပဲ) ...

return [{
    json: {
        cart_status: cartStatus,
        total_items: totalItems,
        oos_count: outOfStockCount,
        available_items: availableItems,
        oos_items: oosItems,
        sender_id: items[0].sender_id,
        // 👇 အောက်က (၄) ကြောင်းကို အသစ်ထပ်ဖြည့်လိုက်တာပါ
        customer_name: items[0].customer_name || '',
        customer_phone: items[0].customer_phone || '',
        customer_address: items[0].customer_address || '',
        payment_method: items[0].payment_method || ''
    }
}];

